import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  // ⭐ Function to render stars with half support
  const renderStars = (rating) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      if (i <= Math.floor(rating)) {
        stars.push(
          <span key={i} style={{ color: "#FFD700", fontSize: "14px", marginRight: "2px" }}>★</span>
        );
      } else if (i === Math.floor(rating) + 1 && rating % 1 >= 0.5) {
        stars.push(
          <span key={i} style={{ color: "#FFD700", fontSize: "14px", marginRight: "2px" }}>⯨</span> // Half star shape
        );
      } else {
        stars.push(
          <span key={i} style={{ color: "#ddd", fontSize: "14px", marginRight: "2px" }}>★</span>
        );
      }
    }
    return stars;
  };

  return (
    <section style={{ padding: "40px" }}>
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      {/* Popular Products Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                padding: "15px",
                background: "#fff",
                height: "200px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3 className="product-name">{item.name}</h3>
            <p style={{ fontSize: "14px", color: "#555" }}>{item.description}</p>
            <p className="product-price">${item.price}</p>

            {/* ⭐ Rating Section */}
            <div style={{ margin: "6px 0", display: "flex", alignItems: "center", justifyContent: "center" }}>
              {renderStars(item.rating)}
              <span style={{ fontSize: "13px", color: "#333", marginLeft: "4px" }}>
                {item.rating}
              </span>
            </div>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#9d5b2e",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>

      {/* Featured Picks Section */}
      <div style={{ marginTop: "60px" }}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✨ Featured Picks
        </h2>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          {[
            {
              title: "Unparalleled Sound",
              desc: "Experience crystal-clear audio with premium headphones.",
              img: "/images/products/feature1.jpg",
            },
            {
              title: "Stay Connected",
              desc: "Compact and stylish earphones for every occasion.",
              img: "/images/products/feature3.jpg",
            },
            {
              title: "Power in Every Pixel",
              desc: "Shop the latest laptops for work, gaming, and more.",
              img: "/images/products/feature5.jpg",
            },
          ].map((card, index) => (
            <div
              key={index}
              style={{
                position: "relative",
                height: "370px",
                backgroundImage: `url(${card.img})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                display: "flex",
                alignItems: "flex-end",
                color: "#fff",
              }}
            >
              <div
                style={{
                  background: "rgba(0,0,0,0.6)",
                  padding: "15px",
                  width: "100%",
                }}
              >
                <h3 style={{ margin: "0 0 10px" }}>{card.title}</h3>
                <p style={{ fontSize: "14px", marginBottom: "10px" }}>
                  {card.desc}
                </p>
                <button
                  style={{
                    padding: "8px 15px",
                    border: "none",
                    background: "#9d5b2e",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  Buy Now ↗
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default PopularProducts;
